  1	import * as React from 'react';
  2	import { DRPolicyKind, DRPlacementControlKind } from '@odf/mco/types';
  3	import { getDRPolicyStatus, parseSyncInterval } from '@odf/mco/utils';
  4	import { formatTime, getLatestDate } from '@odf/shared/details-page/datetime';
  5	import EmptyPage from '@odf/shared/empty-state-page/empty-page';
  6	import { StatusBox } from '@odf/shared/generic/status-box';
  7	import { Labels } from '@odf/shared/labels';
  8	import { ModalBody, ModalFooter } from '@odf/shared/modals/Modal';
  9	import { getAnnotations, getName } from '@odf/shared/selectors';
 10	import { BlueInfoCircleIcon } from '@odf/shared/status';
 11	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 12	import { getErrorMessage } from '@odf/shared/utils';
 13	import {
 14	  GreenCheckCircleIcon,
 15	  StatusIconAndText,
 16	  useK8sWatchResource,
 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import * as _ from 'lodash-es';
 19	import { TFunction, Trans } from 'react-i18next';
 20	import {
 21	  Alert,
 22	  AlertVariant,
 23	  Button,
 24	  ButtonVariant,
 25	  Divider,
 26	  Text,
 27	  TextVariants,
 28	} from '@patternfly/react-core';
 29	import {
 30	  PencilAltIcon,
 31	  UnknownIcon,
 32	  BanIcon,
 33	  ArrowRightIcon,
 34	} from '@patternfly/react-icons';
 35	import {
 36	  DISCOVERED_APP_NS,
 37	  DRApplication,
 38	  IS_CG_ENABLED_ANNOTATION,
 39	  ReplicationType,
 40	  SYNC_SCHEDULE_DISPLAY_TEXT,
 41	  VM_RECIPE_NAME,
 42	} from '../../../constants';
 43	import { getDRPlacementControlResourceObj } from '../../../hooks';
 44	import { unAssignPromises } from './utils/k8s-utils';
 45	import {
 46	  ModalActionContext,
 47	  ModalViewContext,
 48	  ManagePolicyStateType,
 49	} from './utils/reducer';
 50	import { ManagePolicyStateAction } from './utils/reducer';
 51	import {
 52	  DRInfoType,
 53	  DRPlacementControlType,
 54	  DRPolicyType,
 55	  ModalType,
 56	} from './utils/types';
 57	import './style.scss';
 58	
 59	const displayUnknown = (t: TFunction) => (
 60	  <StatusIconAndText
 61	    icon={<UnknownIcon />}
 62	    title={t('Unknown')}
 63	    className="pf-v6-l-flex__item"
 64	  />
 65	);
 66	
 67	const replicationStatus = (label: string, time: string, t: TFunction) => (
 68	  <Text component={TextVariants.p} className="pf-v6-l-flex__item">
 69	    <div className="pf-v6-l-flex">
 70	      {label}{' '}
 71	      {time ? (
 72	        t('Last synced on {{syncTime}}', { syncTime: formatTime(time) })
 73	      ) : (
 74	        <>
 75	          &nbsp;
 76	          {displayUnknown(t)}
 77	        </>
 78	      )}
 79	    </div>
 80	  </Text>
 81	);
 82	enum EmptyPageContentType {
 83	  NamespaceProtected = 'NamespaceProtected',
 84	  Application = 'Application',
 85	  VirtualMachine = 'VirtualMachine',
 86	}
 87	
 88	// Map containing content for each type
 89	const getEmptyPageContentMap = (t: TFunction) => ({
 90	  [EmptyPageContentType.NamespaceProtected]: {
 91	    title: t('Application already enrolled in disaster recovery'),
 92	    content: (
 93	      <Trans t={t}>
 94	        <p>
 95	          This managed application namespace is already DR protected. You may
 96	          have protected this namespace while enrolling discovered applications.
 97	        </p>
 98	        <p className="pf-v6-u-mt-md">
 99	          To see disaster recovery information for your applications, go to
100	          <strong> Protected applications </strong> under&nbsp;
101	          <strong> Disaster Recovery </strong>.
102	        </p>
103	      </Trans>
104	    ),
105	    buttonText: '',
106	  },
107	  [EmptyPageContentType.Application]: {
108	    title: t('No assigned disaster recovery policy found'),
109	    content: (
110	      <Trans t={t}>
111	        <p>
112	          You have not enrolled this application yet. To protect your
113	          application, click&nbsp;
114	          <strong>Enroll application.</strong>
115	        </p>
116	      </Trans>
117	    ),
118	    buttonText: t('Enroll application'),
119	  },
120	  [EmptyPageContentType.VirtualMachine]: {
121	    title: t('No assigned disaster recovery policy found'),
122	    content: (
123	      <Trans t={t}>
124	        <p>
125	          You have not enrolled this virtual machine yet. To protect your
126	          virtual machine, click&nbsp;
127	          <strong>Enroll virtual machine.</strong>
128	        </p>
129	      </Trans>
130	    ),
131	    buttonText: t('Enroll virtual machine'),
132	  },
133	});
134	
135	const isDRProtectionRemoved = (drpcs: DRPlacementControlType[]) =>
136	  drpcs.every((drpc) => _.has(drpc.metadata, 'deletionTimestamp'));
137	
138	const checkNamespaceProtected = (
139	  workloadNamespace: string,
140	  eligiblePolicies: DRPolicyKind[],
141	  drpcs: DRPlacementControlKind[]
142	): boolean =>
143	  drpcs?.some((drpc) => {
144	    const isNamespaceProtected =
145	      drpc.spec?.protectedNamespaces?.includes(workloadNamespace) &&
146	      drpc.spec?.kubeObjectProtection?.recipeRef?.name !== VM_RECIPE_NAME;
147	    const isPolicyMatching = eligiblePolicies?.some(
148	      (policy) => getName(policy) === drpc.spec.drPolicyRef.name
149	    );
150	    return isNamespaceProtected && isPolicyMatching;
151	  });
152	
153	const getAggregatedDRInfo = (
154	  drpcs: DRPlacementControlType[]
155	): AggregatedDRInfo =>
156	  drpcs.reduce(
157	    (acc, drpc) => ({
158	      placements: Array.from(
159	        new Set([...acc.placements, getName(drpc?.placementInfo)])
160	      ),
161	      pvcSelector: [...acc.pvcSelector, ...drpc?.pvcSelector],
162	      lastGroupSyncTime: getLatestDate([
163	        acc.lastGroupSyncTime,
164	        drpc?.lastGroupSyncTime,
165	      ]),
166	      assignedOn: formatTime(
167	        getLatestDate([acc.assignedOn, drpc?.metadata?.creationTimestamp])
168	      ),
169	      lastKubeObjectProtectionTime:
170	        drpc?.lastKubeObjectProtectionTime || acc.lastKubeObjectProtectionTime,
171	      recipeName: drpc?.recipeName || acc.recipeName,
172	      recipeNamespace: drpc?.recipeNamespace || acc.recipeNamespace,
173	      isVolumeGroupReplicationEnabled:
174	        acc.isVolumeGroupReplicationEnabled ||
175	        getAnnotations(drpc)?.[IS_CG_ENABLED_ANNOTATION] === 'true' ||
176	        !_.isEmpty(drpc?.status?.resourceConditions?.resourceMeta?.pvcgroups),
177	    }),
178	    {
179	      placements: [],
180	      pvcSelector: [],
181	      lastGroupSyncTime: '',
182	      assignedOn: '',
183	      recipeName: '',
184	      recipeNamespace: '',
185	      lastKubeObjectProtectionTime: '',
186	      isVolumeGroupReplicationEnabled: false,
187	    }
188	  );
189	
190	const getMessage = (t: TFunction<string>, errorMessage?: string) => ({
191	  [ModalActionContext.ENABLE_DR_PROTECTION_SUCCEEDED]: {
192	    title: t('New policy assigned to application'),
193	    variant: AlertVariant.success,
194	  },
195	  [ModalActionContext.DISABLE_DR_PROTECTION]: {
196	    title: t('Remove disaster recovery'),
197	    variant: AlertVariant.warning,
198	    description: t(
199	      'Your application will lose disaster recovery protection, preventing volume synchronization (replication) between clusters.'
200	    ),
201	  },
202	  [ModalActionContext.DISABLE_DR_PROTECTION_SUCCEEDED]: {
203	    title: t('Disaster recovery removed successfully.'),
204	    variant: AlertVariant.success,
205	  },
206	  [ModalActionContext.DISABLE_DR_PROTECTION_FAILED]: {
207	    title: errorMessage,
208	    variant: AlertVariant.danger,
209	  },
210	});
211	
212	const ManagePolicyEmptyPage: React.FC<ManagePolicyEmptyPageProps> = ({
213	  eligiblePolicies,
214	  workloadNamespace,
215	  policyInfoLoaded,
216	  policyInfoLoadError,
217	  onClick,
218	  modalType,
219	  appType,
220	}) => {
221	  const { t } = useCustomTranslation();
222	  const [discoveredApps, loaded, loadError] = useK8sWatchResource<
223	    DRPlacementControlKind[]
224	  >(
225	    getDRPlacementControlResourceObj({
226	      namespace: DISCOVERED_APP_NS,
227	    })
228	  );
229	
230	  const isNamespaceProtected = checkNamespaceProtected(
231	    workloadNamespace,
232	    eligiblePolicies,
233	    discoveredApps
234	  );
235	
236	  // Determine the correct type dynamically
237	  const emptyPageContentType: EmptyPageContentType = isNamespaceProtected
238	    ? EmptyPageContentType.NamespaceProtected
239	    : modalType === ModalType.VirtualMachine
240	      ? EmptyPageContentType.VirtualMachine
241	      : EmptyPageContentType.Application;
242	
243	  const { title, content, buttonText } =
244	    getEmptyPageContentMap(t)[emptyPageContentType];
245	
246	  const allLoaded = policyInfoLoaded && loaded;
247	  const anyLoadError = policyInfoLoadError || loadError;
248	
249	  return allLoaded && !anyLoadError ? (
250	    <>
251	      {appType === DRApplication.SUBSCRIPTION && (
252	        <Alert
253	          variant={AlertVariant.warning}
254	          isInline
255	          title={t('Subscription deprecated')}
256	          data-test="subscription-deprecation-warning"
257	        >
258	          {t('All processes that use application subscription is deprecated')}
259	        </Alert>
260	      )}
261	      <EmptyPage
262	        isLoaded={allLoaded}
263	        canAccess={true}
264	        isDisabled={isNamespaceProtected}
265	        EmptyIcon={BlueInfoCircleIcon}
266	        onClick={onClick}
267	        buttonText={buttonText}
268	        title={title}
269	      >
270	        {content}
271	      </EmptyPage>
272	    </>
273	  ) : (
274	    <StatusBox loaded={allLoaded} loadError={anyLoadError} />
275	  );
276	};
277	
278	export const DRInformationGroup: React.FC<DRInformationGroupProps> = ({
279	  title,
280	  action,
281	  divider,
282	  children,
283	}) => {
284	  return (
285	    <div className="pf-v6-u-mb-md">
286	      <div className="pf-v6-l-flex">
287	        <Text component={TextVariants.h4} className="pf-v6-l-flex__item">
288	          {title}
289	        </Text>
290	        {!!action && (
291	          <Button
292	            variant={ButtonVariant.link}
293	            icon={action.icon}
294	            onClick={action.onClick}
295	            className="pf-v6-l-flex__item pf-m-align-right"
296	          >
297	            {action.actionText}
298	          </Button>
299	        )}
300	      </div>
301	      {children}
302	      {divider && <Divider className="pf-v6-u-mt-md" />}
303	    </div>
304	  );
305	};
306	
307	const DRInformation: React.FC<DRInformationProps> = ({
308	  dataPolicyInfo,
309	  hideEditAction,
310	  onEdit,
311	  appType,
312	  setModalContext,
313	}) => {
314	  const { t } = useCustomTranslation();
315	  const { drPolicyInfo, placementControlInfo } = dataPolicyInfo;
316	  const { isValidated, replicationType, schedulingInterval, drClusters } =
317	    drPolicyInfo;
318	  const isAsync = replicationType === ReplicationType.ASYNC;
319	  const [unit, interval] = parseSyncInterval(schedulingInterval);
320	  const {
321	    placements,
322	    pvcSelector,
323	    lastGroupSyncTime,
324	    assignedOn,
325	    lastKubeObjectProtectionTime,
326	    recipeName,
327	    recipeNamespace,
328	    isVolumeGroupReplicationEnabled,
329	  } = getAggregatedDRInfo(placementControlInfo);
330	
331	  return (
332	    <>
333	      <DRInformationGroup title={t('Disaster recovery policy details')} divider>
334	        <Text component={TextVariants.p}>
335	          {t('Name: {{name}} ({{status}})', {
336	            name: getName(drPolicyInfo),
337	            status: getDRPolicyStatus(isValidated, t),
338	          })}
339	        </Text>
340	        <Text component={TextVariants.p}>
341	          {isAsync
342	            ? t(
343	                'Replication policy: {{replicationType}}, {{interval}} {{unit}}',
344	                {
345	                  replicationType,
346	                  interval,
347	                  unit: SYNC_SCHEDULE_DISPLAY_TEXT(t)[unit],
348	                }
349	              )
350	            : t('Replication policy: {{replicationType}}', {
351	                replicationType,
352	              })}
353	        </Text>
354	        <Text component={TextVariants.p}>
355	          {t('Cluster: {{clusters}}', { clusters: drClusters.join(', ') })}
356	        </Text>
357	        <Text component={TextVariants.p} className="pf-v6-u-mt-md">
358	          {t('Assigned on: {{assignedOn}}', { assignedOn })}
359	        </Text>
360	      </DRInformationGroup>
361	      <DRInformationGroup
362	        title={t('Protected application resources')}
363	        action={
364	          !hideEditAction
365	            ? {
366	                actionText: t('Edit to add resources'),
367	                icon: <PencilAltIcon />,
368	                onClick: onEdit,
369	              }
370	            : undefined
371	        }
372	        divider
373	      >
374	        <Text component={TextVariants.p}>
375	          {t('Placement: {{placements}}', {
376	            placements: placements.join(', '),
377	          })}
378	        </Text>
379	        {appType !== DRApplication.DISCOVERED ? (
380	          <>
381	            <Text component={TextVariants.p}>{t('Label selector:')}</Text>
382	            <Labels labels={pvcSelector} numLabels={4} />
383	          </>
384	        ) : (
385	          <>
386	            <Text component={TextVariants.p}>
387	              {t('Recipe name: {{recipeName}}', {
388	                recipeName,
389	              })}
390	            </Text>
391	            <Text component={TextVariants.p}>
392	              {t('Recipe namespace: {{recipeNamespace}}', {
393	                recipeNamespace,
394	              })}
395	            </Text>
396	          </>
397	        )}
398	        <VolumeGroupReplicationStatus
399	          isEnabled={isVolumeGroupReplicationEnabled}
400	          setModalContext={setModalContext}
401	        />
402	      </DRInformationGroup>
403	      {(isAsync || appType === DRApplication.DISCOVERED) && (
404	        <DRInformationGroup title={t('Replication details')}>
405	          {isAsync && replicationStatus(t('Volume:'), lastGroupSyncTime, t)}
406	          {replicationStatus(
407	            t('Kubernetes object:'),
408	            lastKubeObjectProtectionTime,
409	            t
410	          )}
411	        </DRInformationGroup>
412	      )}
413	    </>
414	  );
415	};
416	
417	const VolumeGroupReplicationStatus: React.FC<VolumeReplicationStatusProps> = ({
418	  isEnabled,
419	  setModalContext,
420	}) => {
421	  const { t } = useCustomTranslation();
422	  return (
423	    <div className="pf-v6-l-flex">
424	      <Text component={TextVariants.p} className="pf-v6-l-flex__item">
425	        {t('Volume group replication: ')}
426	      </Text>
427	      <StatusIconAndText
428	        icon={isEnabled ? <GreenCheckCircleIcon /> : <BanIcon />}
429	        title={isEnabled ? t('Enabled') : t('Disabled')}
430	        className="pf-v6-l-flex__item"
431	      />
432	      {isEnabled && (
433	        <Button
434	          variant={ButtonVariant.link}
435	          onClick={() =>
436	            setModalContext(ModalViewContext.VOLUME_CONSISTENCY_GROUP_VIEW)
437	          }
438	          className="pf-v6-l-flex__item pf-m-align-right"
439	        >
440	          {t('View volume groups')} <ArrowRightIcon />
441	        </Button>
442	      )}
443	    </div>
444	  );
445	};
446	
447	export const ManagePolicyView: React.FC<ManagePolicyViewProps> = ({
448	  drInfo,
449	  workloadNamespace,
450	  eligiblePolicies,
451	  appType,
452	  unprotectedPlacementCount,
453	  modalActionContext,
454	  loaded,
455	  loadError,
456	  dispatch,
457	  setModalContext,
458	  setModalActionContext,
459	  modalType,
460	  appName,
461	  discoveredVMPVCs,
462	}) => {
463	  const { t } = useCustomTranslation();
464	  const [localModalActionContext, setLocalModalActionContext] =
465	    React.useState<ModalActionContext>(null);
466	  const [errorMessage, setErrorMessage] = React.useState('');
467	  const [inProgress, setInProgress] = React.useState(false);
468	  const actionContext = localModalActionContext ?? modalActionContext;
469	  const alertProps = getMessage(t, errorMessage)?.[actionContext];
470	
471	  if (_.isEmpty(drInfo)) {
472	    return (
473	      <ManagePolicyEmptyPage
474	        eligiblePolicies={eligiblePolicies}
475	        workloadNamespace={workloadNamespace}
476	        policyInfoLoaded={loaded}
477	        policyInfoLoadError={loadError}
478	        onClick={() => {
479	          setModalActionContext(ModalActionContext.ENABLE_DR_PROTECTION);
480	          setModalContext(ModalViewContext.ASSIGN_POLICY_VIEW);
481	        }}
482	        modalType={modalType}
483	        appType={appType}
484	      />
485	    );
486	  }
487	
488	  // To protect new subscription group(s)
489	  const onEdit = () => {
490	    // Set already assigned policy as default
491	    dispatch({
492	      type: ManagePolicyStateType.SET_SELECTED_POLICY,
493	      context: ModalViewContext.ASSIGN_POLICY_VIEW,
494	      payload: drInfo.drPolicyInfo,
495	    });
496	    // Change assign policy view to edit mode
497	    setModalActionContext(ModalActionContext.EDIT_DR_PROTECTION);
498	    // Switch to assign policy view
499	    setModalContext(ModalViewContext.ASSIGN_POLICY_VIEW);
500	  };
501	
502	  const onRemove = async () => {
503	    try {
504	      setInProgress(true);
505	      await unAssignPromises(
506	        drInfo.placementControlInfo,
507	        appName,
508	        workloadNamespace,
509	        appType,
510	        t,
511	        discoveredVMPVCs
512	      );
513	      setLocalModalActionContext(
514	        ModalActionContext.DISABLE_DR_PROTECTION_SUCCEEDED
515	      );
516	    } catch (error) {
517	      setLocalModalActionContext(
518	        ModalActionContext.DISABLE_DR_PROTECTION_FAILED
519	      );
520	      setErrorMessage(getErrorMessage(error) || error);
521	    } finally {
522	      setInProgress(false);
523	    }
524	  };
525	
526	  return (
527	    <>
528	      <ModalBody>
529	        <DRInformation
530	          dataPolicyInfo={drInfo}
531	          hideEditAction={
532	            appType !== DRApplication.SUBSCRIPTION || !unprotectedPlacementCount
533	          }
534	          onEdit={onEdit}
535	          appType={appType}
536	          setModalContext={setModalContext}
537	        />
538	        {!!alertProps && (
539	          <Alert title={alertProps.title} variant={alertProps.variant} isInline>
540	            {alertProps.description}
541	          </Alert>
542	        )}
543	      </ModalBody>
544	      <ModalFooter>
545	        {actionContext !== ModalActionContext.DISABLE_DR_PROTECTION && (
546	          <Button
547	            id="disable-dr-action"
548	            variant={ButtonVariant.secondary}
549	            isDanger
550	            isDisabled={
551	              actionContext ===
552	                ModalActionContext.DISABLE_DR_PROTECTION_SUCCEEDED ||
553	              isDRProtectionRemoved(drInfo.placementControlInfo)
554	            }
555	            onClick={() =>
556	              setLocalModalActionContext(
557	                ModalActionContext.DISABLE_DR_PROTECTION
558	              )
559	            }
560	          >
561	            {t('Remove disaster recovery')}
562	          </Button>
563	        )}
564	        {actionContext === ModalActionContext.DISABLE_DR_PROTECTION && (
565	          <>
566	            <Button
567	              id="cancel-disable-dr-action"
568	              variant={ButtonVariant.secondary}
569	              onClick={() => setLocalModalActionContext(null)}
570	            >
571	              {t('Cancel')}
572	            </Button>
573	            <Button
574	              id="confirm-disable-dr-action"
575	              variant={ButtonVariant.danger}
576	              onClick={onRemove}
577	              isLoading={inProgress}
578	            >
579	              {t('Confirm remove')}
580	            </Button>
581	          </>
582	        )}
583	      </ModalFooter>
584	    </>
585	  );
586	};
587	
588	type ManagePolicyViewProps = {
589	  drInfo: DRInfoType;
590	  workloadNamespace: string;
591	  eligiblePolicies: DRPolicyType[];
592	  appType: DRApplication;
593	  unprotectedPlacementCount: number;
594	  modalActionContext: ModalActionContext;
595	  loaded: boolean;
596	  loadError: any;
597	  dispatch: React.Dispatch<ManagePolicyStateAction>;
598	  setModalContext: (modalViewContext: ModalViewContext) => void;
599	  setModalActionContext: (modalActionContext: ModalActionContext) => void;
600	  modalType: ModalType;
601	  appName: string;
602	  discoveredVMPVCs: string[];
603	};
604	
605	type DRInformationProps = {
606	  dataPolicyInfo: DRInfoType;
607	  hideEditAction: boolean;
608	  onEdit: () => void;
609	  appType: DRApplication;
610	  setModalContext: (modalViewContext: ModalViewContext) => void;
611	};
612	
613	type DRInformationGroupProps = {
614	  title: string;
615	  action?: {
616	    actionText: string;
617	    icon?: React.ReactNode;
618	    onClick: () => void;
619	  };
620	  divider?: boolean;
621	  children?: React.ReactNode;
622	};
623	
624	type ManagePolicyEmptyPageProps = {
625	  workloadNamespace: string;
626	  eligiblePolicies: DRPolicyType[];
627	  policyInfoLoaded: boolean;
628	  policyInfoLoadError: any;
629	  onClick: () => void;
630	  modalType: ModalType;
631	  appType?: DRApplication;
632	};
633	
634	type AggregatedDRInfo = {
635	  placements: string[];
636	  pvcSelector: string[];
637	  lastGroupSyncTime: string;
638	  assignedOn: string;
639	  lastKubeObjectProtectionTime?: string;
640	  recipeName?: string;
641	  recipeNamespace?: string;
642	  isVolumeGroupReplicationEnabled?: boolean;
643	};
644	
645	type VolumeReplicationStatusProps = {
646	  isEnabled: boolean;
647	  setModalContext: (modalViewContext: ModalViewContext) => void;
648	};

