  1	import * as React from 'react';
  2	import { DRPolicyKind, DRPlacementControlKind } from '@odf/mco/types';
  3	import { getDRPolicyStatus, parseSyncInterval } from '@odf/mco/utils';
  4	import { formatTime, getLatestDate } from '@odf/shared/details-page/datetime';
  5	import EmptyPage from '@odf/shared/empty-state-page/empty-page';
  6	import { StatusBox } from '@odf/shared/generic/status-box';
  7	import { Labels } from '@odf/shared/labels';
  8	import { ModalBody, ModalFooter } from '@odf/shared/modals/Modal';
  9	import { getAnnotations, getName } from '@odf/shared/selectors';
 10	import { BlueInfoCircleIcon } from '@odf/shared/status';
 11	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 12	import { getErrorMessage } from '@odf/shared/utils';
 13	import {
 14	  GreenCheckCircleIcon,
 15	  StatusIconAndText,
 16	  useK8sWatchResource,
 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import * as _ from 'lodash-es';
 19	import { TFunction, Trans } from 'react-i18next';
 20	import {
 21	  Alert,
 22	  AlertVariant,
 23	  Button,
 24	  ButtonVariant,
 25	  Divider,
 26	  Text,
 27	  TextVariants,
 28	} from '@patternfly/react-core';
 29	import {
 30	  PencilAltIcon,
 31	  UnknownIcon,
 32	  BanIcon,
 33	  ArrowRightIcon,
 34	} from '@patternfly/react-icons';
 35	import {
 36	  DISCOVERED_APP_NS,
 37	  DRApplication,
 38	  IS_CG_ENABLED_ANNOTATION,
 39	  ReplicationType,
 40	  SYNC_SCHEDULE_DISPLAY_TEXT,
