307	const DRInformation: React.FC<DRInformationProps> = ({
308	  dataPolicyInfo,
309	  hideEditAction,
310	  onEdit,
311	  appType,
312	  setModalContext,
313	}) => {
314	  const { t } = useCustomTranslation();
315	  const { drPolicyInfo, placementControlInfo } = dataPolicyInfo;
316	  const { isValidated, replicationType, schedulingInterval, drClusters } =
317	    drPolicyInfo;
318	  const isAsync = replicationType === ReplicationType.ASYNC;
319	  const [unit, interval] = parseSyncInterval(schedulingInterval);
320	  const {
321	    placements,
322	    pvcSelector,
323	    lastGroupSyncTime,
324	    assignedOn,
