144	    const isNamespaceProtected =
145	      drpc.spec?.protectedNamespaces?.includes(workloadNamespace) &&
146	      drpc.spec?.kubeObjectProtection?.recipeRef?.name !== VM_RECIPE_NAME;
147	    const isPolicyMatching = eligiblePolicies?.some(
148	      (policy) => getName(policy) === drpc.spec.drPolicyRef.name
149	    );
150	    return isNamespaceProtected && isPolicyMatching;
