448	export const ManagePolicyView: React.FC<ManagePolicyViewProps> = ({
449	  drInfo,
450	  workloadNamespace,
451	  eligiblePolicies,
452	  appType,
453	  unprotectedPlacementCount,
454	  modalActionContext,
455	  loaded,
456	  loadError,
457	  dispatch,
458	  setModalContext,
459	  setModalActionContext,
460	  modalType,
461	  appName,
462	  discoveredVMPVCs,
463	}) => {
464	  const { t } = useCustomTranslation();
465	  const [localModalActionContext, setLocalModalActionContext] =
466	    React.useState<ModalActionContext>(null);
467	  const [errorMessage, setErrorMessage] = React.useState('');
468	  const [inProgress, setInProgress] = React.useState(false);
469	  const actionContext = localModalActionContext ?? modalActionContext;
470	  const alertProps = getMessage(t, errorMessage)?.[actionContext];
471	
472	  if (_.isEmpty(drInfo)) {
473	    return (
474	      <ManagePolicyEmptyPage
475	        eligiblePolicies={eligiblePolicies}
476	        workloadNamespace={workloadNamespace}
477	        policyInfoLoaded={loaded}
478	        policyInfoLoadError={loadError}
479	        onClick={() => {
480	          setModalActionContext(ModalActionContext.ENABLE_DR_PROTECTION);
481	          setModalContext(ModalViewContext.ASSIGN_POLICY_VIEW);
482	        }}
483	        modalType={modalType}
484	        appType={appType}
485	      />
486	    );
487	  }
488	
489	  // To protect new subscription group(s)
490	  const onEdit = () => {
491	    // Set already assigned policy as default
492	    dispatch({
493	      type: ManagePolicyStateType.SET_SELECTED_POLICY,
494	      context: ModalViewContext.ASSIGN_POLICY_VIEW,
495	      payload: drInfo.drPolicyInfo,
496	    });
497	    // Change assign policy view to edit mode
498	    setModalActionContext(ModalActionContext.EDIT_DR_PROTECTION);
499	    // Switch to assign policy view
500	    setModalContext(ModalViewContext.ASSIGN_POLICY_VIEW);
501	  };
502	
503	  const onRemove = async () => {
504	    try {
505	      setInProgress(true);
506	      await unAssignPromises(
507	        drInfo.placementControlInfo,
508	        appName,
509	        workloadNamespace,
510	        appType,
511	        t,
512	        discoveredVMPVCs
513	      );
514	      setLocalModalActionContext(
515	        ModalActionContext.DISABLE_DR_PROTECTION_SUCCEEDED
516	      );
517	    } catch (error) {
518	      setLocalModalActionContext(
519	        ModalActionContext.DISABLE_DR_PROTECTION_FAILED
520	      );
521	      setErrorMessage(getErrorMessage(error) || error);
522	    } finally {
523	      setInProgress(false);
524	    }
525	  };
526	
527	  return (
528	    <>
529	      <ModalBody>
530	        <DRInformation
531	          dataPolicyInfo={drInfo}
532	          hideEditAction={
533	            appType !== DRApplication.SUBSCRIPTION || !unprotectedPlacementCount
534	          }
535	          onEdit={onEdit}
536	          appType={appType}
537	          setModalContext={setModalContext}
538	        />
539	        {!!alertProps && (
540	          <Alert title={alertProps.title} variant={alertProps.variant} isInline>
541	            {alertProps.description}
542	          </Alert>
543	        )}
544	      </ModalBody>
545	      <ModalFooter>
546	        {actionContext !== ModalActionContext.DISABLE_DR_PROTECTION && (
547	          <Button
548	            id="disable-dr-action"
549	            variant={ButtonVariant.secondary}
550	            isDanger
551	            isDisabled={
552	              actionContext ===
553	                ModalActionContext.DISABLE_DR_PROTECTION_SUCCEEDED ||
554	              isDRProtectionRemoved(drInfo.placementControlInfo)
555	            }
556	            onClick={() =>
557	              setLocalModalActionContext(
558	                ModalActionContext.DISABLE_DR_PROTECTION
559	              )
560	            }
561	          >
562	            {t('Remove disaster recovery')}
563	          </Button>
564	        )}
565	        {actionContext === ModalActionContext.DISABLE_DR_PROTECTION && (
566	          <>
567	            <Button
568	              id="cancel-disable-dr-action"
569	              variant={ButtonVariant.secondary}
570	              onClick={() => setLocalModalActionContext(null)}
571	            >
572	              {t('Cancel')}
573	            </Button>
574	            <Button
575	              id="confirm-disable-dr-action"
576	              variant={ButtonVariant.danger}
577	              onClick={onRemove}
578	              isLoading={inProgress}
579	            >
580	              {t('Confirm remove')}
581	            </Button>
582	          </>
583	        )}
584	      </ModalFooter>
585	    </>
586	  );
587	};
